      "name": "semesters",
      "type": "STRING",
      "description": "逗號分隔的學年期代碼（如 1142,1141）",
      "default": null
    },
    {
      "name": "degree_type",
      "type": "STRING",
      "description": "學制：U=大學部, G=研究生",
      "default": null
    }
  ]
}

